import React from 'react';

const Gallery = () => {
  return (
    <div className="p-4 grid grid-cols-3 gap-4">
      <h1>Gallery</h1>
      <img src="/images/safari1.jpg" alt="Safari" className="w-full" />
      <img src="/images/safari2.jpg" alt="Tiger" className="w-full" />
    </div>
  );
};

export default Gallery;
